arguments.command:
DBG="/tmp/sv-3be7c1ccc461462894e8ae40e7b2c413/symbols/libmonosgen-2.0.so.dbg"

# Check which section these addresses belong to
aarch64-linux-gnu-readelf -S "$DBG" 2>/dev/null | awk '
/\[/ {
  if (match($0, /\] \.([^ ]+)/, name_arr)) {
    # Extract address and size - look for hex fields
    n = split($0, fields)
    for (i = 1; i <= n; i++) {
      if (fields[i] ~ /^[0-9a-f]{16}$/ || fields[i] ~ /^[0-9a-f]{8}$/) {
        addr = strtonum("0x" fields[i])
        size = strtonum("0x" fields[i+1])
        if (addr > 0 && size > 0 && addr <= 0x2f4b20 && addr + size > 0x2f4b20) {
          printf "0x2f4b20 is in section .%s (0x%x - 0x%x)\n", name_arr[1], addr, addr+size
        }
        break
      }
    }
  }
}'

# Simpler: just show sections
echo "=== Sections ==="
aarch64-linux-gnu-readelf -S "$DBG" 2>/dev/null | grep -E '^\s+\[' | awk '{print $2, $3, $4, $5, $6, $7}' | head -30

